    44→const normalizeProfileLayout = (layout) => {
    45→    const incomingSections = Array.isArray(layout?.sections) ? layout.sections : [];
    46→    const normalizedSections = [];
    47→
    48→    incomingSections.forEach((section) => {
    49→        if(!PROFILE_SECTION_IDS.includes(section?.id)){
    50→            return;
    51→        }
    52→        if(normalizedSections.find((item) => item.id === section.id)){
    53→            return;
    54→        }
    55→
    56→        normalizedSections.push({
    57→            id: section.id,
    58→            visible: section.visible !== false,
    59→            size: PROFILE_SECTION_SIZES.includes(section?.size) ? section.size : 'md'
    60→        });
    61→    });
    62→
    63→    PROFILE_SECTION_IDS.forEach((sectionId) => {
    64→        if(normalizedSections.find((section) => section.id === sectionId)){
    65→            return;
    66→        }
    67→
    68→        const defaultSection = DEFAULT_PROFILE_LAYOUT.sections.find((section) => section.id === sectionId);
    69→        normalizedSections.push({...defaultSection});
    70→    });
    71→
    72→    return {
    73→        version: layout?.version || DEFAULT_PROFILE_LAYOUT.version,
    74→        preset: layout?.preset || DEFAULT_PROFILE_LAYOUT.preset,
    75→        spacing: layout?.spacing || DEFAULT_PROFILE_LAYOUT.spacing,
    76→        radius: layout?.radius || DEFAULT_PROFILE_LAYOUT.radius,
    77→        sections: normalizedSections,
    78→        widgets: (Array.isArray(layout?.widgets) ? layout.widgets : [])
    79→            .filter((widget) => widget && typeof widget === 'object')
    80→            .map((widget) => ({
    81→                id: widget.id || `widget_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
    82→                type: PROFILE_WIDGET_TYPES.includes(normalizeWidgetType(widget.type)) ? normalizeWidgetType(widget.type) : 'note',
    83→                size: PROFILE_SECTION_SIZES.includes(widget.size) ? widget.size : 'md',
    84→                title: typeof widget.title === 'string' ? widget.title : '',
    85→                note: typeof widget.note === 'string' ? widget.note : '',
    86→                image_url: typeof widget.image_url === 'string' ? widget.image_url : '',
    87→                x: Number.isFinite(widget?.x) ? widget.x : 24,
    88→                y: Number.isFinite(widget?.y) ? widget.y : 24,
    89→                width: Number.isFinite(widget?.width) ? widget.width : null,
    90→                height: Number.isFinite(widget?.height) ? widget.height : null,
