     1→import { isPhotoNoteType } from "./constants";
     2→
     3→export const estimateWidgetHeight = (widget) => {
     4→    if (Number.isFinite(widget?.height)) {
     5→        return widget.height;
     6→    }
     7→
     8→    if (Array.isArray(widget?.blocks) && widget.blocks.length > 0) {
     9→        const blockBottom = widget.blocks.reduce(
    10→            (maxBottom, block) =>
    11→                Math.max(
    12→                    maxBottom,
    13→                    (Number.isFinite(block?.y) ? block.y : 0) +
    14→                        (Number.isFinite(block?.height) ? block.height : 40)
    15→                ),
    16→            0
    17→        );
    18→        return Math.max(170, blockBottom + 12);
    19→    }
    20→
    21→    let height = widget.size === "lg" ? 220 : widget.size === "sm" ? 130 : 170;
    22→
    23→    if (isPhotoNoteType(widget?.type) && widget.image_url) {
    24→        const resolvedImageHeight = Number.isFinite(widget?.image_height)
    25→            ? widget.image_height
    26→            : 120;
    27→        height += resolvedImageHeight;
    28→    }
    29→
    30→    if (widget.note) {
    31→        height += Math.min(120, Math.ceil(widget.note.length / 60) * 20);
    32→    }
    33→
    34→    return height;
    35→};
    36→
    37→export const getWidgetBlockCanvasStyle = (widget) => {
    38→    const blocks = Array.isArray(widget?.blocks) ? widget.blocks : [];
    39→    const maxBottom = blocks.reduce(
    40→        (bottom, block) =>
    41→            Math.max(
    42→                bottom,
    43→                (Number.isFinite(block?.y) ? block.y : 0) +
    44→                    (Number.isFinite(block?.height) ? block.height : 40)
    45→            ),
    46→        0
    47→    );
    48→    const baseStyle = {
    49→        minHeight: `${Math.max(60, maxBottom + 8)}px`,
    50→    };
    51→
    52→    if (widget?.pinned_section) {
    53→        return baseStyle;
    54→    }
    55→
    56→    const maxRight = blocks.reduce(
    57→        (right, block) =>
    58→            Math.max(
    59→                right,
    60→                (Number.isFinite(block?.x) ? block.x : 0) +
    61→                    (Number.isFinite(block?.width) ? block.width : 160)
    62→            ),
    63→        0
    64→    );
    65→    const minWidthBySize = widget?.size === "sm" ? 220 : widget?.size === "lg" ? 420 : 300;
    66→
    67→    return {
    68→        ...baseStyle,
    69→        minWidth: `${Math.min(520, Math.max(minWidthBySize, maxRight + 8))}px`,
    70→    };
    71→};
    72→
    73→export const estimateSectionHeight = (sectionId, size) => {
    74→    if (sectionId === "stats") {
    75→        return size === "lg" ? 120 : size === "sm" ? 78 : 96;
    76→    }
    77→
    78→    if (sectionId === "bio") {
    79→        return size === "lg" ? 118 : size === "sm" ? 74 : 96;
    80→    }
    81→
    82→    return size === "lg" ? 72 : size === "sm" ? 52 : 62;
    83→};
